import sqlite3

class Database:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()
        self.create_table()

    def create_table(self):
        self.cursor.execute("""
            CREATE TABLE IF NOT EXISTS urls
            (id INTEGER PRIMARY KEY, original_url TEXT, short_code TEXT UNIQUE, clicks INTEGER DEFAULT 0)
        """)
        self.conn.commit()

    def get_url(self, short_code):
        self.cursor.execute("SELECT original_url, clicks FROM urls WHERE short_code = ?", (short_code,))
        return self.cursor.fetchone()

    def get_analytics(self, short_code):
        self.cursor.execute("SELECT clicks FROM urls WHERE short_code = ?", (short_code,))
        return self.cursor.fetchone()

    def update_clicks(self, short_code):
        self.cursor.execute("UPDATE urls SET clicks = clicks + 1 WHERE short_code = ?", (short_code,))
        self.conn.commit()

    def insert_url(self, original_url, short_code):
        self.cursor.execute("INSERT INTO urls (original_url, short_code) VALUES (?, ?)", (original_url, short_code))
        self.conn.commit()

from fastapi import FastAPI, HTTPException, RedirectResponse
from fastapi.responses import JSONResponse
import sqlite3
from app.db import Database
import string
import secrets

app = FastAPI()

db = Database('urls.db')

@app.post("/shorten")
def shorten_url(original_url: str):
    short_code = ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(6))
    while db.cursor.execute("SELECT * FROM urls WHERE short_code = ?", (short_code,)).fetchone() is not None:
        short_code = ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(6))
    db.insert_url(original_url, short_code)
    return {'short_code': short_code}

@app.get("/{short_code}")
def redirect_url(short_code: str):
    url = db.get_url(short_code)
    if url is None:
        raise HTTPException(status_code=404, detail="URL not found")
    db.update_clicks(short_code)
    return RedirectResponse(url=url[0])

@app.get("/analytics/{short_code}")
def get_analytics(short_code: str):
    analytics = db.get_analytics(short_code)
    if analytics is None:
        raise HTTPException(status_code=404, detail="URL not found")
    return {'clicks': analytics[0]}
